    """
    In Graph ALRT, we don't have a Step x Block matrix, but we can use 
    this method to initialize the L x L Dependency Matrix with specific 
    fixed path segments.
    """
    self.top_fixed = top_fixed
    self.bottom_fixed = bottom_fixed

    with torch.no_grad():
        D = torch.zeros((self.n_layer, self.n_layer), device=self.dependency_matrix.device)
        # Standard sequential dependencies
        for i in range(1, self.n_layer):
            D[i, i-1] = 1.0

        # Create a mask to freeze specific rows of D
        # (If a row is frozen, its block always depends on the previous block sequentialy)
        mask = torch.ones((self.n_layer, self.n_layer), device=self.dependency_matrix.device)

        # Top fixed: Blocks 0 to top_fixed depend purely on predecessor
